            }

            var sql = @"
SELECT TOP (10)
    u.UserId,
    u.Email,
    u.DisplayName,
    u.CreatedUtc
FROM dbo.Users u
WHERE (@UserId IS NULL OR u.UserId = @UserId)
  AND (@Email IS NULL OR u.Email = @Email)
ORDER BY u.CreatedUtc DESC;";

            var parameters = new List<SqlParameter>
            {
                new SqlParameter("@UserId", SqlDbType.NVarChar, 128) { Value = (object?)input.UserId ?? DBNull.Value },
                new SqlParameter("@Email", SqlDbType.NVarChar, 256) { Value = (object?)input.Email ?? DBNull.Value }
            };

            LogDbQuery(sql, parameters, log);

            using var conn = new SqlConnection(connectionString);
            await conn.OpenAsync(ct);

            using var cmd = conn.CreateCommand();
            cmd.CommandText = sql;
            cmd.CommandType = CommandType.Text;
            foreach (var p in parameters)
                cmd.Parameters.Add(p);

            var results = new List<Dictionary<string, object?>>();
            using var reader = await cmd.ExecuteReaderAsync(ct);
            while (await reader.ReadAsync(ct))
            {
                var row = new Dictionary<string, object?>(StringComparer.OrdinalIgnoreCase);
                for (int i = 0; i < reader.FieldCount; i++)
                {
                    var name = reader.GetName(i);
                    var value = await reader.IsDBNullAsync(i, ct) ? null : reader.GetValue(i);
                    row[name] = value;
                }
                results.Add(row);
            }

            log.LogInformation("DbQueryResult RowCount={RowCount}", results.Count);
            return new { rows = results };
        }

        private static void LogDbQuery(string sql, IEnumerable<SqlParameter> parameters, ILogger log)
