                    p.SqlDbType.ToString(),
                    p.Size,
                    p.Direction.ToString(),
                    p.Value is DBNull ? "NULL" : p.Value);
            }
        }

        private static void LogFullException(Exception ex, ILogger log)
        {
            var current = ex;
